"""Generates RORB GE 6.45 .catg file content from a traversed catchment."""

from .attributes import Basin, Confluence, ReachType
from .traveller import Traveller

# ── string constants ──────────────────────────────────────────────────────────
_GFX_HEADER = (
    "C RORB_GE 6.45\n"
    "C WARNING - DO NOT EDIT THIS FILE OUTSIDE RORB TO ENSURE BOTH GRAPHICAL AND "
    "CATCHMENT DATA ARE COMPATIBLE WITH EACH OTHER\n"
    "C THIS FILE CANNOT BE OPENED IN EARLIER VERSIONS OF RORB GE - CURRENT VERSION IS v6.45\n"
    "C\n"
    "C #FILE COMMENTS\n"
    "C   0\n"
    "C\n"
    "C #SUB-AREA AREA COMMENTS\n"
    "C   0\n"
    "C\n"
    "C #IMPERVIOUS FRACTION COMMENTS\n"
    "C   0\n"
    "C\n"
    "C #BACKGROUND IMAGE\n"
    "C  T  F\n"
    "C\n"
)
_GFX_TAIL = (
    "C\n"
    "C #STORAGES\n"
    "C      0\n"
    "C\n"
    "C #INFLOW/OUTFLOW\n"
    "C      0\n"
    "C\n"
    "C END RORB_GE\n"
    "C\n"
)
_AREA_HEADER = "C Sub Area Data\nC Areas, km**2, of subareas A,B...\n"
_FI_HEADER   = "C Impervious Fraction Data\n"
_TOKEN       = "C"


# ── formatting ────────────────────────────────────────────────────────────────
_NODE_FMT  = {
    'id': '>7', 'x': '>15.3f', 'y': '>15.3f', 'icon': '>15.3f',
    'basin': '>2d', 'end': '>2d', 'ds': '>6', 'name': '<34',
    'area': '>14.6f', 'fi': '>15.6f', 'print': '>3d', 'excess': '>3d', 'comment': '>3d',
}
_REACH_FMT = {
    'id': '>7', 'name': '<9', 'us': '>18', 'ds': '>6',
    'translation': '>15d', 'type': '>2d', 'print': '>2d',
    'length': '>15.3f', 'slope': '>15.3f', 'npoints': '>6d', 'comment': '>3d',
    'x': '>16.3f', 'y': '>16.3f',
}


def _make_table(values, col_width=13, precision='.5f'):
    """Format a list of float strings (plus terminal '-99') into 5-per-row table."""
    out = ""
    for i, val in enumerate(values[:-1]):
        try:
            formatted = format(float(val), f'>{col_width}{precision}')
        except (ValueError, TypeError):
            formatted = f"{str(val):>{col_width}}"
        if i > 0 and i % 5 == 0:
            out += f"\n{formatted},"
        else:
            out += f"{formatted},"
    out += f"\n{values[-1]}"
    return out


# ── VectorBlock ───────────────────────────────────────────────────────────────
class VectorBlock:
    def __init__(self):
        self._storedHydro = []
        self._runningHydro = False
        self._stateVector = []
        self._controlVector = []

    def step(self, traveller: Traveller):
        self._state(traveller)
        self._control(self._stateVector[-1], traveller)

    def build(self, traveller: Traveller) -> str:
        s = "0\n"
        for line in self._controlVector:
            s += f"{line}\n"
        s += self._subAreaStr(traveller)
        s += "\n"
        s += self._fracImpStr(traveller)
        s += "\n"
        return s

    def _state(self, traveller: Traveller):
        i = traveller._pos
        up = traveller.top(i)

        if i == traveller._endSentinel:
            ret = (0, i)
        elif (not self._runningHydro) and isinstance(traveller._catchment._vertices[i], Basin):
            self._runningHydro = True
            traveller.next()
            ret = (1, i)
        elif self._storedHydro and self._storedHydro[-1] == i and self._runningHydro:
            self._storedHydro.pop()
            ret = (4, i)
        elif self._runningHydro and isinstance(traveller._catchment._vertices[i], Basin) and up == i:
            traveller.next()
            ret = (2, i)
        elif self._runningHydro and up != i:
            self._storedHydro.append(i)
            self._runningHydro = False
            traveller.next()
            ret = (3, i)
        elif self._runningHydro and isinstance(traveller._catchment._vertices[i], Confluence) and up == i:
            traveller.next()
            ret = (5, i)
        else:
            traveller.next()
            ret = (0, i)

        self._stateVector.append(ret)

    def _control(self, code: tuple, traveller: Traveller):
        c = code[0]
        if c in (1, 2, 5):
            try:
                r = traveller.getReach(code[1])
                if r.type in (ReachType.NATURAL, ReachType.DROWNED):
                    ret = f"{c},{r.type.value},{r.length() / 1000:.3f},-99"
                else:
                    ret = f"{c},{r.type.value},{r.length() / 1000:.3f},{r.getSlope():.4f},-99"
            except KeyError:
                # outlet node has no downstream reach – emit PRINT + end
                node = traveller.getNode(code[1])
                ret = f"7\n{node.name}\n0"
        elif c in (3, 4):
            ret = str(c)
        else:
            ret = ""
        self._controlVector.append(ret)

    def _subAreaStr(self, traveller: Traveller) -> str:
        areas = []
        for s in self._stateVector:
            if s[0] in (1, 2):
                areas.append(f"{traveller._catchment._vertices[s[1]].area:.5f}")
        areas.append('-99')
        return _AREA_HEADER + _make_table(areas)

    def _fracImpStr(self, traveller: Traveller) -> str:
        fis = []
        for s in self._stateVector:
            if s[0] in (1, 2):
                fis.append(f"{traveller._catchment._vertices[s[1]].fi:.5f}")
        fis.append(' -99')
        header = _FI_HEADER + "1,"
        body = _make_table(fis)
        return header + "\n" + body

    @property
    def state(self):
        return self._stateVector


# ── GraphicsBlock ─────────────────────────────────────────────────────────────
class GraphicsBlock:
    def __init__(self, title: str = ""):
        self._title = title
        self._idMap = {}
        self._nodeVec = []
        self._reachVec = []
        self._nodeID = self._counter()
        self._reachID = self._counter()

    def step(self, code: tuple, traveller: Traveller):
        self._nodeDisplay(code, traveller)
        self._reachDisplay(code, traveller)

    def build(self) -> str:
        self._replaceIDs(self._nodeVec)
        self._replaceIDs(self._reachVec)
        self._normalizeCoords()

        title_line = f"{self._title:<69}\n" if self._title else "\n"
        s = title_line
        s += _GFX_HEADER
        s += "C #NODES\n"
        s += f"{_TOKEN}{len(self._nodeVec):>7}\n"
        for row in self._nodeVec:
            s += _TOKEN
            for key, val in row.items():
                s += format(val, _NODE_FMT[key])
            s += f"\n{_TOKEN}\n"

        s += f"{_TOKEN}\n"
        s += "C #REACHES\n"
        s += f"{_TOKEN}{len(self._reachVec):>7}\n"
        for row in self._reachVec:
            s += _TOKEN
            for key, val in row.items():
                if key in ('x', 'y'):
                    s += f"\n{_TOKEN}"
                s += format(val, _REACH_FMT[key])
            s += "\n"

        s += _GFX_TAIL
        return s

    def _replaceIDs(self, vec):
        for i, row in enumerate(vec):
            for k, v in row.items():
                if v in self._idMap:
                    vec[i][k] = self._idMap[v]

    def _normalizeCoords(self, scale=90.0, shift=2.5):
        if not self._nodeVec:
            return
        xs = [r['x'] for r in self._nodeVec]
        ys = [r['y'] for r in self._nodeVec]
        sx = max(xs) - min(xs) or 1.0
        sy = max(ys) - min(ys) or 1.0
        mn_x, mn_y = min(xs), min(ys)

        for r in self._nodeVec:
            r['x'] = (r['x'] - mn_x) / sx * scale + shift
            r['y'] = (r['y'] - mn_y) / sy * scale + shift
        for r in self._reachVec:
            r['x'] = (r['x'] - mn_x) / sx * scale + shift
            r['y'] = (r['y'] - mn_y) / sy * scale + shift

    def _nodeDisplay(self, code: tuple, traveller: Traveller):
        c, pos = code
        if c not in (1, 2, 5):
            return
        node = traveller.getNode(pos)
        x, y = node.coordinates()
        prnt = 70 if isinstance(node, Confluence) and node.isOut else 0
        ds_node = traveller.getNode(traveller.down(pos))
        ds_tag = f"<{ds_node.name}>"

        tag = f"<{node.name}>"
        data = {
            'id': tag,
            'x': x, 'y': y,
            'icon': 1.0,
            'basin': int(isinstance(node, Basin)),
            'end': int(isinstance(node, Confluence) and node.isOut),
            'ds': ds_tag,
            'name': f" {node.name}",
            'area': node.area if isinstance(node, Basin) else 0.0,
            'fi': node.fi if isinstance(node, Basin) else 0.0,
            'print': prnt, 'excess': 0, 'comment': 0,
        }
        self._idMap[tag] = next(self._nodeID)
        self._nodeVec.append(data)

    def _reachDisplay(self, code: tuple, traveller: Traveller):
        c, pos = code
        if c not in (1, 2, 5):
            return
        try:
            reach = traveller.getReach(pos)
            ep = reach.getEnd().coordinates()
            sp = reach.getStart().coordinates()
            mid_x = (ep[0] + sp[0]) / 2
            mid_y = (ep[1] + sp[1]) / 2

            rtag = f"<{reach.name}>"
            data = {
                'id': rtag,
                'name': f" {reach.name}",
                'us': f"<{traveller.getNode(pos).name}>",
                'ds': f"<{traveller.getNode(traveller.down(pos)).name}>",
                'translation': 0,
                'type': reach.type.value,
                'print': 0,
                'length': reach.length() / 1000,
                'slope': reach.slope,
                'npoints': 1,
                'comment': 0,
                'x': mid_x, 'y': mid_y,
            }
            self._idMap[rtag] = next(self._reachID)
            self._reachVec.append(data)
        except KeyError:
            pass

    @staticmethod
    def _counter():
        i = 0
        while True:
            i += 1
            yield i


# ── Public entry point ────────────────────────────────────────────────────────
def build_catg(traveller: Traveller, title: str = "") -> str:
    """Traverse the catchment and return the complete .catg file string."""
    traveller.next()
    vec = VectorBlock()
    gfx = GraphicsBlock(title=title)

    while traveller._pos != traveller._endSentinel:
        vec.step(traveller)
        gfx.step(vec.state[-1], traveller)

    return gfx.build() + vec.build(traveller)
